#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
int t,n,m,l,vv,a[N],d[N],v[N],p[N],cnt,vis[N];
struct node
{
	int l,r;
	bool operator<(const node other) const
	{
		if(l!=other.l) return l<other.l;
		return r>other.r;
	}
} b[N];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen("detect5.in","r",stdin);
//	freopen("detect5(my).out","w",stdout);
	cin>>t;
	while(t--)
	{
		memset(vis,0,sizeof(vis));
		cnt=0;
		cin>>n>>m>>l>>vv;
		for(int i=1;i<=n;i++) cin>>d[i]>>v[i]>>a[i];
		for(int i=1;i<=m;i++) cin>>p[i];
		for(int i=1;i<=n;i++)
		{
			if(a[i]>0)
			{
				int tmp;
				if(v[i]<=vv) tmp=(vv*vv-v[i]*v[i])/(2*a[i])+d[i];
				else tmp=d[i]-1;
				int l=1,r=m,mid;
				while(l<=r)
				{
					mid=(l+r)/2;
					if(p[mid]>tmp) r=mid-1;
					else l=mid+1;
				}
				if(r==m) continue;
				b[++cnt].l=r+1;
				b[cnt].r=m;
			}
			else 
			{
				int l=1,r=m,mid;
				while(l<=r)
				{
					mid=(l+r)/2;
					if(p[mid]>=d[i]) r=mid-1;
					else l=mid+1;
				}
				if(r==m) continue;
				l=r+1,r=m;
				int tmp=l;
				while(l<=r)
				{
					mid=(l+r)/2;
					double tt=sqrt((double)v[i]*v[i]+(double)2*a[i]*(p[mid]-d[i]));
					if(tt>vv) l=mid+1;
					else r=mid-1;
				}
				if(l==tmp) continue;
				b[++cnt].l=tmp;
				b[cnt].r=l-1;
			}
		}
		sort(b+1,b+1+cnt);
//		for(int i=1;i<=cnt;i++) cout<<b[i].l<<" "<<b[i].r<<"aaa\n";
		int mn=0x3f3f3f3f;
		for(int i=cnt;i>=1;i--)
		{
			if(mn<=b[i].r) vis[i]=1;
			mn=min(mn,b[i].r);
		}
		int ans=0,tmp2=0;
		for(int i=1;i<=cnt;i++)
		{
			if(vis[i]) vis[i]=0;
			else if(tmp2<b[i].l)
			{
				ans++;
				tmp2=b[i].r;
			}
		}
		cout<<cnt<<" "<<m-ans<<"\n";
	}
	return 0;
}
